/// Collect a node's flat child list (named, anonymous, extra, error, and
/// missing children alike) in document order: the sequence the
/// reconstruction walk matches the rule's shape against.
fn collect_children<'tree>(node: tree_sitter::Node<'tree>) -> Vec<tree_sitter::Node<'tree>> {
    let mut walker = node.walk();
    node.children(&mut walker).collect()
}
