// Task 7 extract contract: pub fn extract_terminator<'tree>(node: tree_sitter::Node<'tree>) -> TerminatorChildren<'tree>
#[derive(Debug, Clone)]
pub enum TerminatorChoice<'tree> {
    /// Subtype `break_for_coding`.
    BreakForCoding(BreakForCodingNode<'tree>),
    /// Subtype `broken_question`.
    BrokenQuestion(BrokenQuestionNode<'tree>),
    /// Subtype `exclamation`.
    Exclamation(ExclamationNode<'tree>),
    /// Subtype `interrupted_question`.
    InterruptedQuestion(InterruptedQuestionNode<'tree>),
    /// Subtype `interruption`.
    Interruption(InterruptionNode<'tree>),
    /// Subtype `period`.
    Period(PeriodNode<'tree>),
    /// Subtype `question`.
    Question(QuestionNode<'tree>),
    /// Subtype `quoted_new_line`.
    QuotedNewLine(QuotedNewLineNode<'tree>),
    /// Subtype `quoted_period_simple`.
    QuotedPeriodSimple(QuotedPeriodSimpleNode<'tree>),
    /// Subtype `self_interrupted_question`.
    SelfInterruptedQuestion(SelfInterruptedQuestionNode<'tree>),
    /// Subtype `self_interruption`.
    SelfInterruption(SelfInterruptionNode<'tree>),
    /// Subtype `trailing_off`.
    TrailingOff(TrailingOffNode<'tree>),
    /// Subtype `trailing_off_question`.
    TrailingOffQuestion(TrailingOffQuestionNode<'tree>),
}
impl<'tree> AsRawNode<'tree> for TerminatorChoice<'tree> {
    fn raw_node(&self) -> tree_sitter::Node<'tree> {
        match self {
            TerminatorChoice::BreakForCoding(inner) => inner.raw_node(),
            TerminatorChoice::BrokenQuestion(inner) => inner.raw_node(),
            TerminatorChoice::Exclamation(inner) => inner.raw_node(),
            TerminatorChoice::InterruptedQuestion(inner) => inner.raw_node(),
            TerminatorChoice::Interruption(inner) => inner.raw_node(),
            TerminatorChoice::Period(inner) => inner.raw_node(),
            TerminatorChoice::Question(inner) => inner.raw_node(),
            TerminatorChoice::QuotedNewLine(inner) => inner.raw_node(),
            TerminatorChoice::QuotedPeriodSimple(inner) => inner.raw_node(),
            TerminatorChoice::SelfInterruptedQuestion(inner) => inner.raw_node(),
            TerminatorChoice::SelfInterruption(inner) => inner.raw_node(),
            TerminatorChoice::TrailingOff(inner) => inner.raw_node(),
            TerminatorChoice::TrailingOffQuestion(inner) => inner.raw_node(),
        }
    }
}
#[derive(Debug, Clone)]
pub struct TerminatorChildren<'tree> {
    /// The rule's whole content, as a single position: the carrier
    /// convention (spec Section 5) mirroring `fold::slot_of`.
    pub content: Positioned<'tree, NodeSlot<'tree, TerminatorChoice<'tree>>>,
    /// Extras that trail the last child of this node (spec Section 5).
    pub trailing_extras: Vec<Extra<'tree>>,
    /// Children that filled no grammar position: the Unexpected sink
    /// (spec Section 7). Never dropped.
    pub unexpected: Vec<tree_sitter::Node<'tree>>,
}
/// Classify this supertype node by its own kind (spec Section 7).
#[must_use]
pub fn extract_terminator<'tree>(node: tree_sitter::Node<'tree>) -> TerminatorChildren<'tree> {
    let __slot = if node.is_error() {
        NodeSlot::Error(node)
    } else if node.is_missing() {
        NodeSlot::Missing(node)
    } else {
        match node.kind() {
            "break_for_coding" => {
                NodeSlot::Present(TerminatorChoice::BreakForCoding(BreakForCodingNode(node)))
            }
            "broken_question" => {
                NodeSlot::Present(TerminatorChoice::BrokenQuestion(BrokenQuestionNode(node)))
            }
            "exclamation" => {
                NodeSlot::Present(TerminatorChoice::Exclamation(ExclamationNode(node)))
            }
            "interrupted_question" => NodeSlot::Present(TerminatorChoice::InterruptedQuestion(
                InterruptedQuestionNode(node),
            )),
            "interruption" => {
                NodeSlot::Present(TerminatorChoice::Interruption(InterruptionNode(node)))
            }
            "period" => NodeSlot::Present(TerminatorChoice::Period(PeriodNode(node))),
            "question" => NodeSlot::Present(TerminatorChoice::Question(QuestionNode(node))),
            "quoted_new_line" => {
                NodeSlot::Present(TerminatorChoice::QuotedNewLine(QuotedNewLineNode(node)))
            }
            "quoted_period_simple" => NodeSlot::Present(TerminatorChoice::QuotedPeriodSimple(
                QuotedPeriodSimpleNode(node),
            )),
            "self_interrupted_question" => NodeSlot::Present(
                TerminatorChoice::SelfInterruptedQuestion(SelfInterruptedQuestionNode(node)),
            ),
            "self_interruption" => NodeSlot::Present(TerminatorChoice::SelfInterruption(
                SelfInterruptionNode(node),
            )),
            "trailing_off" => {
                NodeSlot::Present(TerminatorChoice::TrailingOff(TrailingOffNode(node)))
            }
            "trailing_off_question" => NodeSlot::Present(TerminatorChoice::TrailingOffQuestion(
                TrailingOffQuestionNode(node),
            )),
            _ => NodeSlot::Unexpected(node),
        }
    };
    TerminatorChildren {
        content: Positioned {
            leading_extras: Vec::new(),
            slot: __slot,
        },
        trailing_extras: Vec::new(),
        unexpected: Vec::new(),
    }
}

